index d967813075bb..de59b5107e92 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -21104,6 +21104,8 @@ static bool compareCmp(Value *V, Value *V2, TargetLibraryInfo &TLI,
     auto *Op2 = CI2->getOperand(CI2Preds ? I : E - I - 1);
     if (Op1 == Op2)
       continue;
+    if (!Op1 || !Op2)
+      return false;
     if (Op1->getValueID() < Op2->getValueID())
       return !IsCompatibility;
     if (Op1->getValueID() > Op2->getValueID())
@@ -21147,9 +21149,12 @@ bool SLPVectorizerPass::vectorizeCmpInsts(iterator_range<ItT> CmpInsts,
   for (CmpInst *I : CmpInsts) {
     if (R.isDeleted(I))
       continue;
